#[test]
fn user_class_new_staticmethod_docs_cover_core_runtime() {
    let diff_name = "cpython_user_class_new_staticmethod_diff_subset";
    let subset_name = "cpython_user_class_new_staticmethod_subset";

    assert!(
        CPYTHON_DIFF.contains(&format!("fn {diff_name}(")),
        "user class __new__ CPython diff evidence must exist"
    );
    assert!(
        CPYTHON_SUBSET.contains(&format!("fn {subset_name}(")),
        "user class __new__ runtime subset evidence must exist"
    );

    for required in [
        "def __new__(cls, x):",
        "type(A.__dict__['__new__']).__name__",
        "type(A.__new__).__name__",
        "return 42",
        "return object.__new__(D)",
        "new only",
        "@classmethod",
        "classmethod-new",
        "class FloatNew(float):",
        "return float.__new__(cls, value + 1)",
    ] {
        assert!(
            CPYTHON_DIFF.contains(required) && CPYTHON_SUBSET.contains(required),
            "user class __new__ diff and subset evidence must both cover `{required}`"
        );
    }
    for required in [
        "\"staticmethod\"",
        "\"function\"",
        "\"new A 3\"",
        "\"init A 3\"",
        "\"42\"",
        "\"C init D\"",
        "\"new only 9\"",
        "\"classmethod-new TypeError\"",
        "\"float-new FloatNew 1.5\"",
        "\"float-init FloatNew 1.5\"",
        "\"FloatNew 2.5 True 0x1.4000000000000p+1\"",
    ] {
        assert!(
            CPYTHON_SUBSET.contains(required),
            "user class __new__ subset output must pin CPython behavior `{required}`"
        );
    }

    for document in [CPYTHON_COVERAGE, CPYTHON_MIGRATION] {
        for required in [
            diff_name,
            subset_name,
            "user-defined `__new__` construction",
            "automatic `staticmethod` wrapping for class-body `__new__`",
            "builtin-subclass `__new__` staticmethod path",
            "`__init__` only when `__new__` returns a matching instance",
        ] {
            assert!(
                document.contains(required),
                "user class __new__ docs must contain `{required}`"
            );
        }
    }
}

#[test]
fn list_rich_search_docs_cover_container_runtime() {
    let diff_name = "cpython_list_rich_search_diff_subset";
    let subset_name = "cpython_list_rich_search_subset";

    assert!(
        CPYTHON_DIFF.contains(&format!("fn {diff_name}(")),
        "list rich search CPython diff evidence must exist"
    );
    assert!(
        CPYTHON_SUBSET.contains(&format!("fn {subset_name}(")),
        "list rich search runtime subset evidence must exist"
    );

    for required in [
        "def __eq__(self, other):",
        "Probe(\"a\") in [Probe(\"a\")]",
        ".__contains__(Probe(\"a\"))",
        "items.count(Probe(\"a\"))",
        "items.index(Probe(\"b\"))",
        "items.index(Probe(\"a\"), 1)",
        "items.remove(Probe(\"a\"))",
        "raise ValueError(\"boom\")",
    ] {
        assert!(
            CPYTHON_DIFF.contains(required) && CPYTHON_SUBSET.contains(required),
            "list rich search diff and subset evidence must both cover `{required}`"
        );
    }
    for required in [
        "\"eq a a\"",
        "\"eq b a\"",
        "\"2 b a\"",
        "\"contains ValueError boom\"",
        "\"count ValueError boom\"",
        "\"index ValueError boom\"",
        "\"remove ValueError boom\"",
    ] {
        assert!(
            CPYTHON_SUBSET.contains(required),
            "list rich search subset output must pin CPython behavior `{required}`"
        );
    }
    for required in [
        "fn list_item_matches(",
        "fn list_contains_rich(",
        "fn list_find_rich(",
        "fn call_list_search_method(",
    ] {
        assert!(
            VM_SOURCE.contains(required),
            "list rich search VM implementation must contain `{required}`"
        );
    }

    for document in [CPYTHON_COVERAGE, CPYTHON_MIGRATION] {
        for required in [
            diff_name,
            subset_name,
            "list membership, `__contains__`,",
            "`count`, `index`, and `remove` dispatch through user-defined `__eq__`",
            "comparison-exception propagation",
        ] {
            assert!(
                document.contains(required),
                "list rich search docs must contain `{required}`"
            );
        }
    }
}

#[test]
fn list_index_missing_valueerror_message_subset_has_focused_diff_evidence() {
    for required in [
        "fn cpython_list_index_missing_valueerror_message_subset(",
        "lambda: [1, 2].index(3)",
        "lambda: L([1, 2]).index(3)",
        "lambda: [1, 2].index(Needle())",
        "lambda: [1, 2, 3].index(3, 0, 2)",
        "list.index(x): x not in list",
        "\"repr-needle ValueError list.index(x): x not in list ('list.index(x): x not in list',)\"",
        "\"window ValueError list.index(x): x not in list ('list.index(x): x not in list',)\"",
    ] {
        assert!(
            CPYTHON_SUBSET.contains(required),
            "focused list.index missing ValueError subset evidence must cover `{required}`"
        );
    }

    let body = extract_rust_test_body(
        CPYTHON_DIFF,
        "cpython_list_index_missing_valueerror_message_diff_subset",
    );
    for required in [
        "Lib/test/list_tests.py list.index missing value ValueError message subset",
        "name: \"list-index-missing-valueerror-message\"",
        "lambda: [1, 2].index(3)",
        "lambda: L([1, 2]).index(3)",
        "lambda: [1, 2].index(Needle())",
        "lambda: [1, 2, 3].index(3, 0, 2)",
        "print(label, type(error).__name__, str(error), error.args)",
    ] {
        assert!(
            body.contains(required),
            "focused list.index missing ValueError CPython diff evidence must cover `{required}`"
        );
    }

    assert!(
        VM_SOURCE.contains("ValueError: list.index(x): x not in list"),
        "list.index missing value implementation must keep CPython's fixed public message"
    );
    assert!(
        !VM_SOURCE.contains("ValueError: {needle} is not in list"),
        "list.index missing value implementation must not format the missing needle into the public message"
    );

    for document in [CPYTHON_COVERAGE, CPYTHON_MIGRATION] {
        assert!(
            document.contains("cpython_list_index_missing_valueerror_message_subset")
                && document.contains("cpython_list_index_missing_valueerror_message_diff_subset")
                && document.contains("list.index(x): x not in list"),
            "focused list.index missing ValueError evidence must be documented in coverage and migration notes"
        );
    }
}

#[test]
fn list_index_bounds_index_subset_has_focused_diff_evidence() {
    let subset = extract_rust_test_body(CPYTHON_SUBSET, "cpython_list_index_bounds_index_subset");
    let diff = extract_rust_test_body(CPYTHON_DIFF, "cpython_list_index_bounds_index_diff_subset");

    for required in [
        "class Indexable:",
        "def __index__(self):",
        "class Big:",
        "class NegBig:",
        "class Bad:",
        "class Boom:",
        "[1, 2, 3].index(2, Indexable(1))",
        "[1, 2, 3].index(3, 0, Indexable(1))",
        "[1, 2, 3].index(1, Big())",
        "[1, 2, 3].index(1, NegBig())",
        "[1, 2, 3].index(1, Bad())",
        "[1, 2, 3].index(1, Boom())",
        "[1, 2, 3].index(1, 'x')",
        "slice indices must be integers or have an __index__ method",
    ] {
        assert!(
            subset.contains(required) && diff.contains(required),
            "list.index bound __index__ subset and diff evidence must cover `{required}`"
        );
    }
    assert!(
        diff.contains("Lib/test/list_tests.py list.index start/stop __index__ subset"),
        "list.index bound __index__ diff evidence must cite the CPython origin"
    );
    for required in [
        "\"start-index 1\"",
        "\"stop-index ValueError list.index(x): x not in list\"",
        "\"negative-start 0\"",
        "\"big-start ValueError list.index(x): x not in list\"",
        "\"negative-big-start 0\"",
        "\"bad-index TypeError __index__ returned non-int (type str)\"",
        "\"boom-index ValueError boom\"",
        "\"string-bound TypeError slice indices must be integers or have an __index__ method\"",
    ] {
        assert!(
            subset.contains(required),
            "list.index bound __index__ runtime evidence must pin `{required}`"
        );
    }

    for required in [
        "fn list_search_bound_argument(",
        "self.list_search_bound_argument(value)?",
        "slice indices must be integers or have an __index__ method",
        "integer_dunder_result(\"__index__\", result)",
    ] {
        assert!(
            VM_SOURCE.contains(required),
            "list.index bound implementation must contain `{required}`"
        );
    }

    for document in [CPYTHON_COVERAGE, CPYTHON_MIGRATION] {
        for required in [
            "cpython_list_index_bounds_index_subset",
            "cpython_list_index_bounds_index_diff_subset",
            "`list.index()` start/stop bounds",
            "`__index__`",
            "slice indices must be integers or have an __index__ method",
        ] {
            assert!(
                document.contains(required),
                "list.index bound __index__ docs must contain `{required}`"
            );
        }
    }
}

