#[test]
fn cpython_test_manifest_summary_matches_source_groups() {
    let groups = manifest_groups();
    let summary = summary_rows();

    let total_groups: usize = summary.values().map(|(groups, _)| groups).sum();
    let total_methods: usize = summary.values().map(|(_, methods)| methods).sum();

    assert_eq!(groups.len(), total_groups, "summary group total drifted");
    assert_eq!(
        groups.iter().map(|group| group.methods).sum::<usize>(),
        total_methods,
        "summary method total drifted"
    );

    for (status, (summary_groups, summary_methods)) in summary {
        let actual_groups = groups.iter().filter(|group| group.status == status).count();
        let actual_methods = groups
            .iter()
            .filter(|group| group.status == status)
            .map(|group| group.methods)
            .sum::<usize>();
        assert_eq!(
            actual_groups, summary_groups,
            "summary group count drifted for `{status}`"
        );
        assert_eq!(
            actual_methods, summary_methods,
            "summary method count drifted for `{status}`"
        );
    }
}

#[test]
fn cpython_test_manifest_keeps_unfinished_scope_visible() {
    let summary = summary_rows();
    let unfinished_statuses = [
        ("partial", 4, 219),
        ("blocked_by_runtime", 4, 13),
        ("blocked_by_ast_module", 2, 16),
        ("blocked_by_cpython_internal", 5, 10),
    ];

    for (status, expected_groups, expected_methods) in unfinished_statuses {
        let (groups, methods) = summary
            .get(status)
            .copied()
            .unwrap_or_else(|| panic!("summary must include unfinished status `{status}`"));
        assert_eq!(
            (groups, methods),
            (expected_groups, expected_methods),
            "unfinished manifest status `{status}` drifted"
        );
        assert!(
            groups > 0 && methods > 0,
            "unfinished manifest status `{status}` must stay visible until the goal is actually complete"
        );
    }

    assert_eq!(
        summary.get("not_started").copied(),
        Some((0, 0)),
        "not_started rows should stay at zero; remaining work must be classified as partial or blocked"
    );

    for required in [
        "partial",
        "blocked_by_runtime",
        "blocked_by_ast_module",
        "blocked_by_cpython_internal",
        "full method-level parity has not been proven",
        "MiniPython does not yet implement",
        "CPython-internal",
    ] {
        assert!(
            CPYTHON_MIGRATION.contains(required),
            "migration notes must keep unfinished scope term `{required}` visible"
        );
    }
}

#[test]
fn cpython_test_manifest_partial_methods_have_explicit_stop_line_reason() {
    let partials = all_method_audit_methods()
        .into_iter()
        .filter(|method| method.status == "partial")
        .collect::<Vec<_>>();
    let actual = partials
        .iter()
        .map(|method| method.method.to_string())
        .collect::<BTreeSet<_>>();
    let expected = [
        "test_ascii",
        "test_getattr",
        "test_type_name",
        "test_type_doc",
    ]
    .into_iter()
    .map(String::from)
    .collect::<BTreeSet<_>>();
    assert_eq!(
        actual, expected,
        "method-level partial rows must stay limited to explicit stop-line gaps"
    );

    for method in partials {
        let context = format!("{} {}", method.evidence, method.remaining);
        assert!(
            context.contains("surrogate")
                || context.contains("pdb")
                || context.contains("breakpoint")
                || context.contains("locale"),
            "partial method `{}` must document a concrete stop-line reason, got `{context}`",
            method.method
        );
    }

    for required in ["lone-surrogate", "pdb", "breakpoint", "locale-sensitive"] {
        assert!(
            CPYTHON_COVERAGE.contains(required) || CPYTHON_MIGRATION.contains(required),
            "coverage or migration notes must keep partial stop-line term `{required}` visible"
        );
    }
}

