#[test]
fn copy_sandbox_manifest_lists_public_subset_evidence() {
    assert_sandbox_manifest_subset_evidence(
        "copy",
        &[
            "cpython_copy_public_subset",
            "cpython_copy_replace_custom_hook_subset",
            "cpython_copy_replace_unsupported_type_error_subset",
            "cpython_copy_replace_hook_unexpected_keyword_error_subset",
            "cpython_copy_replace_classmethod_hook_arity_error_subset",
            "cpython_copy_replace_staticmethod_hook_arity_error_subset",
        ],
        &["pickle protocol"],
    );

    let row = sandbox_stdlib_rows()
        .into_iter()
        .find(|row| row.module == "copy")
        .expect("sandbox stdlib manifest must include copy");
    for evidence in [
        "cpython_copy_public_diff_subset",
        "cpython_copy_replace_custom_hook_diff_subset",
        "cpython_copy_replace_unsupported_type_error_diff_subset",
        "cpython_copy_replace_hook_unexpected_keyword_error_diff_subset",
        "cpython_copy_replace_classmethod_hook_arity_error_diff_subset",
        "cpython_copy_replace_staticmethod_hook_arity_error_diff_subset",
        "cpython_array_one_byte_public_copy_byteswap_compare_diff_subset",
    ] {
        assert!(
            row.diff_evidence.contains(evidence),
            "copy sandbox manifest must cite CPython diff evidence `{evidence}`"
        );
    }

    assert!(
        LANGUAGE_TESTS.contains("copy_sandbox_subset_excludes_pickle_dispatch_internals")
            && LANGUAGE_TESTS.contains(
                "'_copy_dispatch', '_deepcopy_dispatch', '_keep_alive', '_reconstruct', '__all__'"
            )
            && LANGUAGE_TESTS.contains("dir(copy)"),
        "copy sandbox export test must guard pickle dispatch internals and module __all__"
    );
}

